          flex: 1;
        }

        .jaydev-container .section {
          margin-bottom: 25px;
        }

        .jaydev-container .section-title {
          font-size: 14pt;
          font-weight: 900;
          color: #000080;
          margin-bottom: 5px;
          letter-spacing: 1.5px;
        }

        .jaydev-container .sidebar-title {
          font-size: 12pt;
        }

        .jaydev-container .title-line {
          height: 2px;
          background: #000080;
          margin-bottom: 12px;
          width: 100%;
        }

        .jaydev-container .item {
          margin-bottom: 15px;
        }

        .jaydev-container .item-header {
          display: flex;
          justify-content: space-between;
          align-items: baseline;
          margin-bottom: 3px;
        }

        .jaydev-container .item-title {
          font-size: 12pt;
          font-weight: 900;
          color: #333;
        }

        .jaydev-container .item-company {
          font-size: 11pt;
