          color: #000080;
        }

        .jaydev-container .item-meta {
          font-size: 9pt;
          color: #666;
          display: flex;
          justify-content: space-between;
          font-style: italic;
        }

        .jaydev-container .bullets {
          margin-top: 5px;
          padding-left: 18px;
          list-style-type: disc;
        }

        .jaydev-container .bullets li {
          margin-bottom: 4px;
          padding-left: 5px;
        }

        .jaydev-container .divider {
          height: 1px;
          background: #e0e0e0;
          width: 80%;
