          margin-top: 2px;
        }

        .jaydev-container .skill-group {
          margin-bottom: 12px;
        }

        .jaydev-container .skill-group-title {
          font-size: 9pt;
          font-weight: 900;
          color: #000080;
          margin-bottom: 8px;
          text-transform: uppercase;
        }

        .jaydev-container .skill-tags {
          display: flex;
          flex-wrap: wrap;
          gap: 6px;
        }

        .jaydev-container .skill-tag {
          font-size: 8.5pt;
          font-weight: 700;
          color: #000080;
          border: 1.5px solid #000080;
          padding: 3px 10px;
          border-radius: 4px;
          background: white;
        }

        .jaydev-container .strengths-list {
          display: flex;
